/* === User subroutine section === */

static void comment(void) {
    int c;

    while ((c = input()) != 0) {
        if (c == '\n') {
            line_num++;
            column = 0;
            continue;
        }

        if (c == '\t') {
            column += 8 - (column % 8);
        } else {
            column++;
        }

        if (c == '*') {
            while ((c = input()) == '*') {
                column++;
            }
            if (c == '/') {
                column++;
                return;
            }
            if (c == 0) {
                break;
            }
            if (c == '\n') {
                line_num++;
                column = 0;
            } else if (c == '\t') {
                column += 8 - (column % 8);
            } else {
                column++;
            }
        }
    }
}

static void count(void) {
    int i;
    int fl = line_num;
    int fc = column;

    for (i = 0; yytext[i] != '\0'; i++) {
        if (yytext[i] == '\n') {
            line_num++;
            column = 0;
        } else if (yytext[i] == '\t') {
            column += 8 - (column % 8);
        } else {
            column++;
        }
    }
    yylloc.first_line = fl;
    yylloc.first_column = fc;
    yylloc.last_line = line_num;
    yylloc.last_column = column;
}

static int check_type(void) {
    Symbol *symbol = symbol_lookup(yytext);

#ifdef TYPE_NAME
    if (symbol != NULL && symbol->type == TYPE_NAME) {
        return TYPE_NAME;
    }
#endif

    if (symbol != NULL && symbol->type > 0) {
        return symbol->type;
    }

    return IDENTIFIER;
}

